  static async new_from_data(type_: GLibVariantType, data_: Array<number>, trusted: boolean, session_id: string, callback_secret: string, notify: GLibDestroyNotify, user_data?: Pointer): Promise<GLibVariant> {
    // Increment ref for parameters with full transfer ownership
    const url = new URL(`${apiConfig.normalizedBasePath}/GLib/Variant/new_from_data`, apiConfig.baseUrl);
    // Object with explode=false: serialize as comma-separated
    if (type_ && typeof type_ === 'object' && 'ptr' in type_) {
      url.searchParams.append('type', 'ptr,' + type_.ptr);
    }
    // Primitive parameter
    url.searchParams.append('data', String(data_));
    // Primitive parameter
    url.searchParams.append('trusted', String(trusted));
    // Primitive parameter
    if (user_data !== undefined) url.searchParams.append('user_data', String(user_data));
    // Register callback using the callback handler
    let notify_callbackInfo: { callbackUrl: string; callbackId: string } | undefined;
    if (typeof notify !== 'undefined') {
      const callbackHandler = getCallbackHandler();
      if (!callbackHandler) {
        throw new Error('Callback handler not configured. Call setCallbackHandler() first.');
      }
      
      // Register the callback with its converter function
      notify_callbackInfo = callbackHandler.registerCallback(
        notify, 
        convertGLibDestroyNotifyArgs,
        {
          methodName: 'new_from_data',
          paramName: 'notify'
        }
      );
      
      // Pass the callback URL to the server
      url.searchParams.append('notify', notify_callbackInfo.callbackUrl);
    }
    try {
      // Add headers for callback authentication
      const headers: Record<string, string> = {};
      if (session_id) {
        headers['session-id'] = session_id;
      }
      if (callback_secret) {
        headers['callback-secret'] = callback_secret;
      }
      
      // Auto-inject correlation ID if we're in a callback context
      const correlationId = getActiveCorrelationId();
      if (correlationId) {
        headers['X-Correlation-Id'] = correlationId;
      }
      
      const response = await fetch(url.toString(), { headers });
      if (!response.ok) {
        // If the call fails, unref the objects we ref'd
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const data = await response.json();
    // Return value is a struct, instantiate it from the ptr
if (data.return && typeof data.return === 'object' && 'ptr' in data.return) {
const instance = await GLibVariant.create(data.return.ptr, 'none');
  return instance;
}
return Promise.reject("Call failed");


    } catch (error) {
      // If there's an error, unref the objects we ref'd
      throw error;
    }
  }

    







 
